INSERT INTO pages (slug, title, meta_json) VALUES ('', 'Hope On Studio — Publishing · Photography · Learning Design', '{"description":"Hope On Studio is the creative practice of one maker across three crafts: artistic books and journals, photography, and learning design.","ground":"ink"}')
  ON CONFLICT(slug) DO UPDATE SET title = excluded.title, meta_json = excluded.meta_json;
INSERT INTO revisions (page_id, status, blocks_json, published_at)
  SELECT id, 'published', '[{"id":"landing-hero","type":"hero","props":{"kicker":"A Studio of Three Crafts","title":"HOPE ON\nSTUDIO","subtitle":"Books that feel like keepsakes. Photographs that keep their breath. Learning that people carry with them.","image":{"src":"/assets/art/hero-bloom-field.jpg","alt":"A field of soft botanicals rendered in halftone dots"},"meta":{"left":"THREE CRAFTS · ONE HAND","right":"PUBLISHING · PHOTOGRAPHY · LEARNING DESIGN"}}},{"id":"landing-manifesto","type":"manifesto","props":{"kicker":"The Practice","heading":"Made slowly,\non purpose.","body":"Hope On Studio is a one-woman practice devoted to things worth keeping — pages you dog-ear, prints you frame, lessons you remember years later.\n\nThree crafts, one hand. Everything here is designed with patience, edited with courage, and finished only when it feels inevitable.","accent":"rule"}},{"id":"landing-triptych","type":"outlet-triptych","props":{"kicker":"Three Creative Outlets","panels":[{"outlet":"publishing","title":"Publishing","tagline":"Artistic books & journals that ask to be held.","image":{"src":"/assets/art/outlet-publishing.jpg","alt":"An open journal with pressed flowers on cream paper"},"bloom":"iris"},{"outlet":"photography","title":"Photography","tagline":"Quiet images with long memories.","image":{"src":"/assets/art/outlet-photography.jpg","alt":"A muted still-life photograph in soft window light"},"bloom":"coral"},{"outlet":"learning-design","title":"Learning Design","tagline":"Courses built the way good stories are.","image":{"src":"/assets/art/outlet-learning.jpg","alt":"Hand-drawn course blueprint with fine ink lines"},"bloom":"gold"}]}},{"id":"landing-scatter","type":"scatter-words","props":{"sentence":"Every project begins the same way — with a small stubborn hope that it can be beautiful","emphasis":["hope","beautiful"]}},{"id":"landing-gallery","type":"gallery-flow","props":{"kicker":"From the Studio","items":[{"image":{"src":"/assets/art/gallery-01.jpg","alt":"Journal spread with botanical illustration"},"size":"lg","treatment":"halftone","rotation":-2},{"image":{"src":"/assets/art/gallery-02.jpg","alt":"Still-life photograph of paper and petals"},"size":"md","treatment":"photo","rotation":1.5},{"image":{"src":"/assets/art/gallery-03.jpg","alt":"Course storyboard sketches"},"size":"sm","treatment":"photo","rotation":3},{"image":{"src":"/assets/art/gallery-04.jpg","alt":"Cloth-bound book cover with foil title"},"size":"md","treatment":"halftone","rotation":-1},{"image":{"src":"/assets/art/gallery-05.jpg","alt":"Contact sheet of muted photographs"},"size":"lg","treatment":"photo","rotation":2}]}},{"id":"landing-quote","type":"quote-bloom","props":{"quote":"Hope is a discipline —\nyou practice it in ink, in light, in the way you teach.","attribution":"the studio''s founding line"}},{"id":"landing-marquee","type":"marquee","props":{"phrases":["NEW JOURNALS IN THE MAKING","PRINTS COMING TO THE SHOP","COURSES IN QUIET DEVELOPMENT","COMMISSIONS OPEN SOON"]}},{"id":"landing-faq","type":"faq-scatter","props":{"kicker":"Asked & Answered","items":[{"q":"Who is behind Hope On Studio?","a":"One maker, three crafts. The studio is a single pair of hands — which is exactly why everything matches."},{"q":"Do you take commissions?","a":"Soon. Custom journals, portrait sessions, and course design engagements will each open in their own season."},{"q":"Where does the name come from?","a":"From the habit of saying it out loud on hard days: hope on. It stuck, and then it became a practice."}]}},{"id":"landing-contact","type":"contact-card","props":{"kicker":"Correspondence","heading":"Write to the studio","email":"hello@hopeon.studio","socials":[{"label":"Instagram","href":"#"},{"label":"Pinterest","href":"#"}]}},{"id":"landing-footer","type":"footer","props":{"line":"Made slowly, with hope.","meta":"HOPE ON STUDIO — EST. 2026"}}]', datetime('now') FROM pages WHERE slug = '';

-- learning-design.json
INSERT INTO pages (slug, title, meta_json) VALUES ('learning-design', 'Learning Design — Hope On Studio', '{"description":"Course creation and instructional design from Hope On Studio — learning built the way good stories are.","ground":"cream"}')
  ON CONFLICT(slug) DO UPDATE SET title = excluded.title, meta_json = excluded.meta_json;
INSERT INTO revisions (page_id, status, blocks_json, published_at)
  SELECT id, 'published', '[{"id":"ld-hero","type":"hero","props":{"kicker":"Outlet Nº 03 — The Blueprint","title":"LEARNING\nDESIGN","subtitle":"Courses and curricula built the way good stories are — with an arc, a heartbeat, and an ending that lands.","image":{"src":"/assets/art/learning-hero.jpg","alt":"Fine-line course blueprint with annotations"},"meta":{"left":"HOPE ON STUDIO","right":"COURSES · CURRICULA · WORKSHOPS"}}},{"id":"ld-manifesto","type":"manifesto","props":{"kicker":"The Method","heading":"Teaching is\ndesign work.","body":"Most courses are containers. The good ones are journeys — sequenced, paced, and honest about what it feels like to not know something yet.\n\nThe studio designs learning with the same materials as its books and photographs: structure, patience, and respect for the person on the other side.","accent":"rule"}},{"id":"ld-process","type":"process-steps","props":{"kicker":"The Blueprint","heading":"Four moves, every time.","steps":[{"n":"01","title":"Map the distance","body":"Where the learner starts, where they need to arrive, and what the terrain between actually looks like — before a single slide exists."},{"n":"02","title":"Design the arc","body":"Modules are chapters. Each one earns the next, and the difficult middle is paced like a story, not a syllabus."},{"n":"03","title":"Build the moments","body":"Practice, feedback, and small wins placed exactly where motivation usually dies. That placement is the craft."},{"n":"04","title":"Test with real people","body":"A course isn''t finished when the content is in — it''s finished when a stranger gets through it and feels capable."}]}},{"id":"ld-stats","type":"stats-editorial","props":{"kicker":"In Numbers","heading":"What the method holds.","stats":[{"value":"4","suffix":"moves","label":"in every engagement, no exceptions"},{"value":"90","suffix":"%","label":"of course problems are sequencing problems"},{"value":"0","label":"modules shipped without a learner test"}]}},{"id":"ld-gallery","type":"gallery-flow","props":{"kicker":"Artifacts","items":[{"image":{"src":"/assets/art/ld-artifact-01.jpg","alt":"Course journey map with hand annotations"},"size":"lg","treatment":"halftone","rotation":-1.5},{"image":{"src":"/assets/art/ld-artifact-02.jpg","alt":"Storyboard frames for a video lesson"},"size":"md","treatment":"photo","rotation":2},{"image":{"src":"/assets/art/ld-artifact-03.jpg","alt":"Workbook spread with exercises"},"size":"md","treatment":"photo","rotation":-2}]}},{"id":"ld-quote","type":"quote-bloom","props":{"quote":"People don''t finish courses.\nThey finish stories.","attribution":"the studio''s working theory"}},{"id":"ld-contact","type":"contact-card","props":{"kicker":"Engagements","heading":"Design a course together","email":"learning@hopeon.studio","socials":[{"label":"LinkedIn","href":"#"}]}},{"id":"ld-footer","type":"footer","props":{"line":"Made slowly, with hope.","meta":"HOPE ON STUDIO — LEARNING DESIGN"}}]', datetime('now') FROM pages WHERE slug = 'learning-design';

