INSERT INTO pages (slug, title, meta_json) VALUES ('photography', 'Photography — Hope On Studio', '{"description":"Quiet, muted photography from Hope On Studio — portraits, still life, and light kept on purpose.","ground":"ink"}')
  ON CONFLICT(slug) DO UPDATE SET title = excluded.title, meta_json = excluded.meta_json;
INSERT INTO revisions (page_id, status, blocks_json, published_at)
  SELECT id, 'published', '[{"id":"photo-hero","type":"hero","props":{"kicker":"Outlet Nº 02 — The Darkroom","title":"PHOTOGRAPHY","subtitle":"Images developed the old way: patiently, and only the ones worth keeping.","image":{"src":"/assets/art/photography-hero.jpg","alt":"A muted portrait dissolving into halftone grain"},"meta":{"left":"HOPE ON STUDIO","right":"PORTRAIT · STILL LIFE · PLACE"}}},{"id":"photo-manifesto","type":"manifesto","props":{"kicker":"The Eye","heading":"Light, kept\non purpose.","body":"The studio photographs the way it publishes: little, and well. Portraits that let people look like themselves. Still lifes that treat ordinary objects with ceremony. Places at the hour they are most honest.\n\nEvery frame below begins as grain and resolves into light — stay with it.","accent":"rule"}},{"id":"photo-develop-1","type":"particle-image","props":{"image":{"src":"/assets/art/photo-develop-01.jpg","alt":"Still life with cut flowers in morning light"},"caption":"Nº 01 — still life, morning","variant":"assemble","height":"full"}},{"id":"photo-develop-2","type":"particle-image","props":{"image":{"src":"/assets/art/photo-develop-02.jpg","alt":"Window-lit portrait in muted tones"},"caption":"Nº 02 — portrait, window light","variant":"slats","height":"full"}},{"id":"photo-gallery","type":"gallery-flow","props":{"kicker":"Selected Frames","items":[{"image":{"src":"/assets/art/photo-frame-01.jpg","alt":"Botanical shadow on paper"},"size":"md","treatment":"photo","rotation":-2},{"image":{"src":"/assets/art/photo-frame-02.jpg","alt":"Hands holding an open book"},"size":"lg","treatment":"photo","rotation":1},{"image":{"src":"/assets/art/photo-frame-03.jpg","alt":"Quiet interior corner with chair"},"size":"sm","treatment":"halftone","rotation":2.5},{"image":{"src":"/assets/art/photo-frame-04.jpg","alt":"Muted landscape at dusk"},"size":"lg","treatment":"photo","rotation":-1}]}},{"id":"photo-scatter","type":"scatter-words","props":{"sentence":"A photograph is a promise that this light existed and someone stood still for it","emphasis":["light","still"]}},{"id":"photo-quote","type":"quote-bloom","props":{"quote":"Develop only what you\nwant to remember.","attribution":"darkroom rule nº 1"}},{"id":"photo-contact","type":"contact-card","props":{"kicker":"Sessions","heading":"Sit for a portrait","email":"sessions@hopeon.studio","socials":[{"label":"Instagram","href":"#"}]}},{"id":"photo-footer","type":"footer","props":{"line":"Made slowly, with hope.","meta":"HOPE ON STUDIO — PHOTOGRAPHY"}}]', datetime('now') FROM pages WHERE slug = 'photography';

-- publishing.json
INSERT INTO pages (slug, title, meta_json) VALUES ('publishing', 'Publishing — Hope On Studio', '{"description":"Artistic books and journals from Hope On Studio — designed with patience, bound to be kept.","ground":"cream"}')
  ON CONFLICT(slug) DO UPDATE SET title = excluded.title, meta_json = excluded.meta_json;
INSERT INTO revisions (page_id, status, blocks_json, published_at)
  SELECT id, 'published', '[{"id":"pub-hero","type":"hero","props":{"kicker":"Outlet Nº 01 — Paper & Ink","title":"PUBLISHING","subtitle":"Books and journals made to be held, written in, and handed down.","image":{"src":"/assets/art/publishing-hero.jpg","alt":"A stack of cloth-bound journals with botanical endpapers"},"meta":{"left":"HOPE ON STUDIO","right":"BOOKS · JOURNALS · EPHEMERA"}}},{"id":"pub-manifesto","type":"manifesto","props":{"kicker":"The Craft","heading":"A book is a\nslow object.","body":"In a world of feeds, a book refuses to scroll. Every title from the studio is composed like a keepsake: paper chosen by touch, margins that let the words breathe, covers that age gracefully.\n\nJournals are designed as invitations — structured enough to begin, open enough to become yours.","accent":"rule"}},{"id":"pub-gallery","type":"gallery-flow","props":{"kicker":"Spreads & Bindings","items":[{"image":{"src":"/assets/art/pub-spread-01.jpg","alt":"Open spread with pressed-flower illustrations"},"size":"lg","treatment":"halftone","rotation":-1.5},{"image":{"src":"/assets/art/pub-spread-02.jpg","alt":"Typography detail with drop cap"},"size":"md","treatment":"photo","rotation":2},{"image":{"src":"/assets/art/pub-spread-03.jpg","alt":"Journal prompts page in serif type"},"size":"md","treatment":"photo","rotation":-2.5},{"image":{"src":"/assets/art/pub-spread-04.jpg","alt":"Foil-stamped cover on linen cloth"},"size":"sm","treatment":"halftone","rotation":1}]}},{"id":"pub-process","type":"process-steps","props":{"kicker":"How a Title Happens","heading":"From whisper to shelf.","steps":[{"n":"01","title":"Listen","body":"Every book starts as a sentence that refuses to leave. It gets a notebook of its own and a season to prove itself."},{"n":"02","title":"Compose","body":"Words and images are set together like a table for guests — nothing crowded, nothing cold."},{"n":"03","title":"Bind","body":"Materials are chosen last, on purpose: paper, cloth, and thread that match what the pages already believe."}]}},{"id":"pub-stats","type":"stats-editorial","props":{"kicker":"The Shelf So Far","heading":"Small numbers, kept promises.","stats":[{"value":"3","suffix":"titles","label":"in quiet development"},{"value":"120","suffix":"gsm","label":"the lightest paper we will ever print on"},{"value":"1","label":"rule — never publish anything we wouldn''t keep"}]}},{"id":"pub-quote","type":"quote-bloom","props":{"quote":"Some pages are doors.","attribution":"on why the studio publishes at all"}},{"id":"pub-contact","type":"contact-card","props":{"kicker":"For Readers & Stockists","heading":"Ask about the first titles","email":"press@hopeon.studio","socials":[{"label":"Instagram","href":"#"}]}},{"id":"pub-footer","type":"footer","props":{"line":"Made slowly, with hope.","meta":"HOPE ON STUDIO — PUBLISHING"}}]', datetime('now') FROM pages WHERE slug = 'publishing';

